module  omsp_clock_gate (
    gclk,                      
    clk,                       
    enable,                    
    scan_enable                
);
output         gclk;           
input          clk;            
input          enable;         
input          scan_enable;    
wire    disable_out =   (enable | scan_enable);
reg     enable_latch;
always @(clk or disable_out)
  if (~clk)
    enable_latch <= disable_out;
assign  gclk      =  (clk & enable_latch);
endmodule
